97	// Returns reserved word ID if the lowercase word starting at pos matches,
98	// or -1 if not a reserved word. Sets *end to position past the word.
99	int lookup_reserved(char *src, int pos, int *end) {
100	    int len;
101	
102	    len = str_match(src, pos, "rho");
103	    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_RHO; }
