150	// ---- Tokenizer ----
151	// Tokenize input line into tok_type/tok_val/tok_pos arrays.
152	// Returns number of tokens (also stored in tok_count).
153	// On error, returns -1 (unrecognized character).
154	int tokenize(char *line) {
155	    int i = 0;
156	    int t = 0;
157	
158	    while (line[i] && t < TOK_MAX - 1) {
159	        // Skip whitespace
160	        if (line[i] == 32) {
161	            i++;
162	            continue;
163	        }
164	
165	        // Number: digits, or underscore followed by digit (APL negative)
166	        if (is_digit(line[i]) || (line[i] == 95 && is_digit(line[i + 1]))) {
167	            tok_type[t] = TOK_NUM;
168	            tok_pos[t] = i;
169	            int end;
170	            tok_val[t] = parse_int(line, i, &end);
171	            i = end;
172	            t++;
173	            continue;
174	        }
175	
176	        // Lowercase letter: quad variables, reserved word, or unknown
177	        if (is_lower(line[i])) {
178	            // Check for quad variables first
179	            int len;
180	            len = str_match(line, i, "qled");
181	            if (len == 4 && !is_alnum(line[i + 4])) {
182	                tok_type[t] = TOK_QLED;
183	                tok_pos[t] = i;
184	                tok_val[t] = 0;
185	                t++;
186	                i = i + 4;
187	                continue;
188	            }
189	
190	            len = str_match(line, i, "qsw");
191	            if (len == 3 && !is_alnum(line[i + 3])) {
192	                tok_type[t] = TOK_QSW;
193	                tok_pos[t] = i;
194	                tok_val[t] = 0;
195	                t++;
196	                i = i + 3;
197	                continue;
198	            }
199	
200	            len = str_match(line, i, "qsvo");
201	            if (len == 4 && !is_alnum(line[i + 4])) {
202	                tok_type[t] = TOK_QSVO;
203	                tok_pos[t] = i;
204	                tok_val[t] = 0;
205	                t++;
206	                i = i + 4;
207	                continue;
208	            }
209	
210	            len = str_match(line, i, "qrl");
211	            if (len == 3 && !is_alnum(line[i + 3])) {
212	                tok_type[t] = TOK_QRL;
213	                tok_pos[t] = i;
214	                tok_val[t] = 0;
215	                t++;
216	                i = i + 3;
217	                continue;
218	            }
219	
220	            len = str_match(line, i, "qout");
221	            if (len == 4 && !is_alnum(line[i + 4])) {
222	                tok_type[t] = TOK_QOUT;
223	                tok_pos[t] = i;
224	                tok_val[t] = 0;
225	                t++;
226	                i = i + 4;
227	                continue;
228	            }
229	
230	            len = str_match(line, i, "qdl");
231	            if (len == 3 && !is_alnum(line[i + 3])) {
232	                tok_type[t] = TOK_QDL;
233	                tok_pos[t] = i;
234	                tok_val[t] = 0;
235	                t++;
236	                i = i + 3;
237	                continue;
238	            }
239	
240	            len = str_match(line, i, "goto");
241	            if (len == 4 && !is_alnum(line[i + 4])) {
242	                tok_type[t] = TOK_GOTO;
243	                tok_pos[t] = i;
244	                tok_val[t] = 0;
245	                t++;
246	                i = i + 4;
247	                continue;
248	            }
249	
250	            int end;
251	            int res = lookup_reserved(line, i, &end);
252	            if (res >= 0) {
253	                tok_type[t] = TOK_RES;
254	                tok_val[t] = res;
255	                tok_pos[t] = i;
256	                i = end;
257	                t++;
258	                continue;
259	            }
260	            // Unknown lowercase word -- error
261	            return -1;
262	        }
263	
264	        // String literal: 'ABC' (single-quoted, for qsvo left argument)
265	        if (line[i] == 39) {
266	            // 39 = single quote
267	            i++;
268	            tok_type[t] = TOK_STRING;
269	            tok_pos[t] = i;  // position of first char
270	            tok_val[t] = i;  // store start of string content
271	            while (line[i] && line[i] != 39) i++;
272	            if (line[i] != 39) return -1;  // unterminated string
273	            i++;  // skip closing quote
274	            t++;
275	            continue;
276	        }
277	
278	        // Uppercase letter: user identifier
279	        if (is_upper(line[i])) {
280	            tok_type[t] = TOK_IDENT;
281	            tok_pos[t] = i;
282	            tok_val[t] = i;  // store start position for name extraction
283	            i++;
284	            while (is_alnum(line[i])) i++;
285	            t++;
286	            continue;
287	        }
288	
289	        // Operators and punctuation
290	        if (line[i] == 43) { tok_type[t] = TOK_PLUS;   tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
291	        if (line[i] == 45) { tok_type[t] = TOK_MINUS;  tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
292	        if (line[i] == 42) { tok_type[t] = TOK_STAR;   tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
293	        if (line[i] == 47) { tok_type[t] = TOK_SLASH;  tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
294	        if (line[i] == 40) { tok_type[t] = TOK_LPAREN; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
295	        if (line[i] == 41) { tok_type[t] = TOK_RPAREN; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
296	
297	        // Quad: [] (IBM 5100 ASCII convention for ⎕) or bracket indexing [expr]
298	        if (line[i] == 91) {
299	            if (line[i + 1] == 93) {
300	                // [] = quad
301	                tok_type[t] = TOK_QUAD;
302	                tok_pos[t] = i;
303	                tok_val[t] = 0;
304	                t++;
305	                i = i + 2;
306	            } else {
307	                // [ = bracket index open
308	                tok_type[t] = TOK_LBRAK;
309	                tok_pos[t] = i;
310	                tok_val[t] = 0;
311	                t++;
312	                i++;
313	            }
314	            continue;
315	        }
316	        if (line[i] == 93) {
317	            tok_type[t] = TOK_RBRAK;
318	            tok_pos[t] = i;
319	            tok_val[t] = 0;
320	            t++;
321	            i++;
322	            continue;
323	        }
324	
325	        // Assignment: <-
326	        if (line[i] == 60 && line[i + 1] == 45) {
327	            tok_type[t] = TOK_ASSIGN;
328	            tok_pos[t] = i;
329	            tok_val[t] = 0;
330	            t++;
331	            i = i + 2;
332	            continue;
333	        }
334	
335	        // Comparison operators: = != >= <= > <
336	        // 61 '='  33 '!'  62 '>'  60 '<'
337	        if (line[i] == 61) { tok_type[t] = TOK_EQ; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
338	        if (line[i] == 33 && line[i + 1] == 61) { tok_type[t] = TOK_NE; tok_pos[t] = i; tok_val[t] = 0; t++; i = i + 2; continue; }
339	        if (line[i] == 62 && line[i + 1] == 61) { tok_type[t] = TOK_GE; tok_pos[t] = i; tok_val[t] = 0; t++; i = i + 2; continue; }
340	        if (line[i] == 60 && line[i + 1] == 61) { tok_type[t] = TOK_LE; tok_pos[t] = i; tok_val[t] = 0; t++; i = i + 2; continue; }
341	        if (line[i] == 62) { tok_type[t] = TOK_GT; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
342	        if (line[i] == 60) { tok_type[t] = TOK_LT; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
343	
344	        // Unrecognized character
345	        return -1;
346	    }
347	
348	    // Append EOL sentinel
349	    tok_type[t] = TOK_EOL;
350	    tok_pos[t] = i;
351	    tok_val[t] = 0;
352	    t++;
353	    tok_count = t;
354	    return t;
355	}
356	
357	// ---- Debug: print token list ----
358	// Useful for testing the tokenizer in isolation.
359	void tok_dump(char *line) {
360	    int i = 0;
361	    while (i < tok_count) {
362	        int ty = tok_type[i];
363	        if (ty == TOK_EOL) {
364	            io_print("EOL");
365	        } else if (ty == TOK_NUM) {
366	            io_print("NUM:");
367	            print_int(tok_val[i]);
368	        } else if (ty == TOK_IDENT) {
369	            io_print("ID:");
370	            int p = tok_val[i];
371	            while (is_alnum(line[p])) {
372	                putchar(line[p]);
373	                p++;
374	            }
375	        } else if (ty == TOK_RES) {
376	            io_print("RES:");
377	            int r = tok_val[i];
378	            if (r == RES_RHO)  io_print("rho");
379	            if (r == RES_IOTA) io_print("iota");
380	            if (r == RES_TAKE) io_print("take");
381	            if (r == RES_DROP) io_print("drop");
382	            if (r == RES_REV)  io_print("rev");
383	            if (r == RES_CAT)  io_print("cat");
384	        } else if (ty == TOK_PLUS)   { putchar(43); }
385	          else if (ty == TOK_MINUS)  { putchar(45); }
386	          else if (ty == TOK_STAR)   { putchar(42); }
387	          else if (ty == TOK_SLASH)  { putchar(47); }
388	          else if (ty == TOK_LPAREN) { putchar(40); }
389	          else if (ty == TOK_RPAREN) { putchar(41); }
390	          else if (ty == TOK_ASSIGN) { io_print("<-"); }
391	
392	        if (tok_type[i + 1] != TOK_EOL || ty == TOK_EOL) {
393	            // nothing
394	        }
395	        if (i + 1 < tok_count) putchar(32);
396	        i++;
397	    }
398	    putchar(10);
399	}
